  6→
  7→export function useComments(
  8→  postId: string,
  9→  receiverId: string | undefined,
 10→  token: string,
 11→  onReplyActivated?: () => void,
 12→) {
 13→  const [commentInput, setCommentInput] = useState('');
 14→  const [replyingTo, setReplyingTo] = useState<{id: string; userName: string} | null>(null);
 15→  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
 16→  const [fetchedReplies, setFetchedReplies] = useState<Record<string, JournalComment[]>>({});
 17→  const [loadingReplies, setLoadingReplies] = useState<Set<string>>(new Set());
 18→
 19→  const commentsQuery = useQuery({
 20→    queryKey: ['journal-comments', postId],
 21→    queryFn: () => socialApi.getComments(postId, null, 20),
 22→    enabled: !!postId,
 23→  });
 24→
 25→  const handleReply = useCallback((commentId: string, userName: string) => {
 26→    setReplyingTo({id: commentId, userName});
 27→    onReplyActivated?.();
 28→  }, [onReplyActivated]);
 29→
 30→  const handleToggleReplies = useCallback((commentId: string) => {
 31→    setExpandedReplies(prev => {
 32→      const next = new Set(prev);
 33→      if (next.has(commentId)) {
 34→        next.delete(commentId);
 35→        return next;
 36→      }
 37→      next.add(commentId);
 38→
 39→      if (!fetchedReplies[commentId]) {
 40→        setLoadingReplies(p => new Set(p).add(commentId));
 41→        socialApi.getReplies(postId, commentId).then(res => {
 42→          setFetchedReplies(p => ({...p, [commentId]: res.comments}));
 43→          setLoadingReplies(p => {
 44→            const n = new Set(p);
 45→            n.delete(commentId);
 46→            return n;
 47→          });
 48→        }).catch(() => {
 49→          setLoadingReplies(p => {
 50→            const n = new Set(p);
 51→            n.delete(commentId);
 52→            return n;
 53→          });
 54→        });
 55→      }
 56→
 57→      return next;
 58→    });
 59→  }, [postId, fetchedReplies]);
 60→
 61→  const addCommentMutation = useMutation({
 62→    mutationFn: async () => {
 63→      const body = commentInput.trim();
 64→      if (!token) throw new Error('Please log in to comment.');
 65→      if (!body) throw new Error('Comment cannot be empty.');
 66→      if (!receiverId) throw new Error('Missing journal owner.');
 67→      return socialApi.addComment(token, {
 68→        comments: body,
 69→        postId,
 70→        receiverId,
 71→        parentId: replyingTo?.id,
 72→      });
 73→    },
 74→    onSuccess: () => {
 75→      const parentId = replyingTo?.id;
 76→      setCommentInput('');
 77→      setReplyingTo(null);
 78→      queryClient.invalidateQueries({queryKey: ['journal-comments', postId]});
 79→      queryClient.invalidateQueries({queryKey: ['journal', postId]});
 80→      queryClient.invalidateQueries({queryKey: ['feed']});
 81→      queryClient.invalidateQueries({queryKey: ['profileWritings']});
 82→      if (parentId) {
 83→        setFetchedReplies(prev => {
 84→          const next = {...prev};
 85→          delete next[parentId];
 86→          return next;
 87→        });
 88→        setExpandedReplies(prev => new Set(prev).add(parentId));
 89→        setLoadingReplies(p => new Set(p).add(parentId));
 90→        socialApi.getReplies(postId, parentId).then(res => {
 91→          setFetchedReplies(p => ({...p, [parentId]: res.comments}));
 92→          setLoadingReplies(p => {
 93→            const n = new Set(p);
 94→            n.delete(parentId);
 95→            return n;
 96→          });
 97→        }).catch(() => {
 98→          setLoadingReplies(p => {
 99→            const n = new Set(p);
100→            n.delete(parentId);
101→            return n;
102→          });
103→        });
104→      }
105→    },
106→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
107→  });
108→
109→  const comments = commentsQuery.data?.comments ?? [];
110→
111→  return {
112→    comments,
113→    isLoading: commentsQuery.isLoading,
114→    commentInput,
115→    setCommentInput,
116→    replyingTo,
117→    setReplyingTo,
118→    expandedReplies,
119→    fetchedReplies,
120→    loadingReplies,
121→    handleReply,
122→    handleToggleReplies,
123→    submitComment: () => addCommentMutation.mutate(),
124→    isSubmitting: addCommentMutation.isPending,
125→  };
126→}
