  setRefreshing(true);
  try { await feedQuery.refetch(); }
  finally { setRefreshing(false); }
};

const handleQuickAction = (key: string) => {
  setActiveFilter(key);
};
```

Note: `handleAuthorPress` in HomeFeedScreen is defined inside the `renderItem` closure, whereas in ExploreScreen it is a module-level arrow function receiving a `JournalItem`.

